package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  private static class DummyRecord {
    public final int x;
    public DummyRecord(int x) { this.x = x; }
  }

  private static class DummyClass {}

  private static Object originalRecordHelper;

  @BeforeAll
  static void setup() throws Exception {
    // Backup original RECORD_HELPER value
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Save original for restoration if needed
    originalRecordHelper = recordHelperField.get(null);

    // Remove final modifier from RECORD_HELPER field to allow reassignment
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);

    // Find private static inner class RecordHelper
    Class<?> recordHelperClass = null;
    for (Class<?> innerClass : ReflectionHelper.class.getDeclaredClasses()) {
      if ("RecordHelper".equals(innerClass.getSimpleName())) {
        recordHelperClass = innerClass;
        break;
      }
    }
    assertNotNull(recordHelperClass, "RecordHelper class not found");

    // Create a subclass of RecordHelper with overridden isRecord method via reflection proxy is not possible
    // Instead, create a dynamic subclass using a proxy-like approach with java.lang.reflect.Proxy is not possible because RecordHelper is a class, not interface
    // So use java.lang.reflect.Proxy is invalid; instead, use a subclass via reflection and override method.

    // Create a new instance of RecordHelper subclass overriding isRecord method
    Object customRecordHelper = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperClass.getClassLoader(),
        new Class<?>[] {},
        (proxy, method, args) -> {
          throw new UnsupportedOperationException("No interface to proxy");
        }
    );

    // Instead, create a subclass dynamically using java.lang.reflect.Proxy is not possible.
    // So create a subclass manually via reflection.

    // Use reflection to get the constructor of RecordHelper and instantiate it
    Object recordHelperInstance = recordHelperClass.getDeclaredConstructor().newInstance();

    // Use java.lang.reflect.Proxy not possible, so create a subclass with overridden method using a library is not allowed.
    // Instead, use java.lang.reflect.InvocationHandler and Proxy only if interface

    // Use java.lang.reflect.Proxy is not possible. Use a proxy-like approach with java.lang.reflect.MethodHandle or similar is complex.

    // Alternative: Use java.lang.reflect.Proxy for an interface that RecordHelper implements if any
    // If none, use reflection to set the RECORD_HELPER field to a custom implementation using a dynamic subclass with overridden method via a library like ByteBuddy or CGLIB
    // But these are not allowed here.

    // Alternative: Use java.lang.reflect.Proxy for an interface implemented by RecordHelper
    // If none, fallback to reflection to set the field to original instance (no change)

    // Since Proxy approach fails, fallback: create a subclass with overridden isRecord method using anonymous class (if accessible)
    // But RecordHelper is private static class, so cannot subclass directly.

    // Instead, use java.lang.reflect.Proxy is impossible, so use reflection to set the field to a custom implementation of RecordHelper via a lambda is impossible.

    // So the best fix is to use a Mockito spy or mock for RecordHelper.

    // Use Mockito to mock the RecordHelper class
    // Mockito 3 supports mocking final classes with inline mock maker enabled.

    // Create mock of RecordHelper class
    Object mockRecordHelper = org.mockito.Mockito.mock(recordHelperClass, invocation -> {
      String methodName = invocation.getMethod().getName();
      if ("isRecord".equals(methodName) && invocation.getArguments().length == 1) {
        Class<?> clazz = (Class<?>) invocation.getArgument(0);
        if (clazz == DummyRecord.class) {
          return true;
        }
        if (clazz == DummyClass.class) {
          return false;
        }
        return false;
      }
      // For other methods, call real method if possible, or throw
      return invocation.callRealMethod();
    });

    // Set the mock instance to the RECORD_HELPER field
    recordHelperField.set(null, mockRecordHelper);
  }

  @Test
  void isRecord_returnsTrue_whenRecordHelperReturnsTrue() {
    assertTrue(ReflectionHelper.isRecord(DummyRecord.class));
  }

  @Test
  void isRecord_returnsFalse_whenRecordHelperReturnsFalse() {
    assertFalse(ReflectionHelper.isRecord(DummyClass.class));
  }
}
